import React from 'react';

const AdminUsers = () => {
  return (
    <div className="p-6">
      <h1 className="text-2xl font-bold mb-6">Manage Users</h1>
      <div className="bg-white rounded-lg shadow p-6">
        <p className="text-gray-600">User management coming soon...</p>
      </div>
    </div>
  );
};

export default AdminUsers;
